err=$out.err
export LC_ALL=C
if [ "$mode" = hdrs ]; then
    # -fdirectives-only speeds up preprocessing but breaks on some edge cases
    # (e.g. __COUNTER__ tricks); retry without it, discarding the first
    # attempt's diagnostics.
    "$@" -fdirectives-only 2> "$err" || "$@" 2> "$err"
