# ninja's `restat` can prune the inclusion check on recompiles that don't alter
# the set of included headers. See issue #1161.
if [ -f "$out" ] && cmp -s "$out.new" "$out"; then
    rm -f "$out.new"
else
    mv "$out.new" "$out"
fi
rm -f "$err"
exit $ec
